import sysfrom pathlib import Pathimport pandas as pd# Ensure project root is on sys.pathPROJECT_ROOT = Path(__file__).resolve().parents[1]if str(PROJECT_ROOT) not in sys.path:    sys.path.insert(0, str(PROJECT_ROOT))from config import PROCESSED_DATA_DIR, TABLE_DIRSPLITS = ["train", "validation", "test"]def compute_stats(df: pd.DataFrame, split_name: str):    n_docs = len(df)    label_counts = df["label_5d"].value_counts().to_dict()    n_pos = label_counts.get(1, 0)    n_neg = label_counts.get(0, 0)    avg_sent = df["n_sentences"].mean()    avg_sec = df["n_sections"].mean()    return {        "split": split_name,        "n_docs": n_docs,        "n_positive": n_pos,        "n_negative": n_neg,        "pos_ratio": n_pos / n_docs if n_docs > 0 else 0,        "avg_sentences": avg_sent,        "avg_sections": avg_sec,    }def main():    results = []    for split in SPLITS:        path = PROCESSED_DATA_DIR / f"{split}_doc_5d_large_lite.parquet"        print(f"\nLoading {path} ...")        df = pd.read_parquet(path)        stats = compute_stats(df, split)        results.append(stats)        print(f"\n--- {split.upper()} ---")        print(f"Documents: {stats['n_docs']:,}")        print(f"Positive:  {stats['n_positive']:,}")        print(f"Negative:  {stats['n_negative']:,}")        print(f"Pos ratio: {stats['pos_ratio']:.3f}")        print(f"Avg sentences: {stats['avg_sentences']:.2f}")        print(f"Avg sections:  {stats['avg_sections']:.2f}")    stats_df = pd.DataFrame(results)    TABLE_DIR.mkdir(parents=True, exist_ok=True)    out_path = TABLE_DIR / "large_lite_dataset_statistics.csv"    stats_df.to_csv(out_path, index=False)    print("\nSaved table to:")    print(out_path)    print("\nFinal table:")    print(stats_df)if __name__ == "__main__":    main()